#include <stdio.h>
#include <string.h>

int countDistinctSubsequences(char * sourceString, char * targetString) {
    int m = strlen(sourceString), n = strlen(targetString);
    int dp[m + 1][n + 1];
    memset(dp, 0, sizeof(dp));
    dp[0][0] = 1;
    for (int i = 0; i <= m; i++) {
        for (int j = 0; j <= n; j++) {
            if (i == 0) {
                if (j == 0) dp[i][j] = 1;
            } else {
                if (j > 0 && sourceString[i - 1] == targetString[j - 1]) {
                    dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j];
                } else {
                    dp[i][j] = dp[i - 1][j];
                }
            }
        }
    }
    return dp[m][n];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char sourceString[1001], targetString[1001];
        scanf("%s %s", sourceString, targetString);
        printf("%d\n", countDistinctSubsequences(sourceString, targetString));
    }
    return 0;
}

